import sys

class Solution:
    def binary_search(self, nums: list[int], target: int) -> bool:
        left, right = 0, len(nums) - 1
        while left <= right:
            mid = (left + right) // 2
            if nums[mid] == target:
                return True
            elif nums[mid] < target:
                left = mid + 1
            else:
                right = mid - 1
        return False

solution = Solution()
s = sys.stdin.readline().strip()
n = int(s)
ts = sys.stdin.readline().strip().split()
target = int(sys.stdin.readline().strip())
print(solution.binary_search(list(map(int, ts)), target))

