#include <iostream>
#include <vector>
#include <sstream>

bool binary_search(std::vector<int>& nums, int target) {
    int left = 0, right = nums.size() - 1;
    while (left <= right) {
        int mid = (left + right) / 2;
        if (nums[mid] == target) {
            return true;
        } else if (nums[mid] < target) {
            left = mid + 1;
        } else {
            right = mid - 1;
        }
    }
    return false;
}

int main() {
    std::string s;
    std::getline(std::cin, s);
    int n = std::stoi(s);
    std::getline(std::cin, s);
    std::istringstream iss(s);
    std::vector<int> nums(n);
    for (int i = 0; i < n; ++i) {
        iss >> nums[i];
    }
    int target;
    std::cin >> target;
    std::cout << std::boolalpha << binary_search(nums, target) << std::endl;
    return 0;
}
